// ============================================================
// NŒUD 2 — Normalize Input
// Valide et normalise les champs entrants depuis Next.js
// ============================================================

const body = $input.first().json.body || $input.first().json;

const message = typeof body.message === 'string' ? body.message.trim() : '';
const sessionId = typeof body.sessionId === 'string' && body.sessionId.length > 0
  ? body.sessionId
  : `session-fallback-${Date.now()}`;

if (!message) {
  return [{
    json: {
      error: true,
      reply: "Message invalide.",
      intent: "unknown",
      stage: "fallback",
      sessionId
    }
  }];
}

// Extraire les données connues du lead
const knownLeadData = body.knownLeadData && typeof body.knownLeadData === 'object'
  ? body.knownLeadData
  : {};

// Extraire le contexte villas envoyé par Next.js
const context = body.context && typeof body.context === 'object'
  ? body.context
  : { villas: [], availableAmenities: [], villaCount: 0 };

return [{
  json: {
    message,
    sessionId,
    locale: body.locale || 'fr',
    source: body.source || 'website_chatbot',
    timestamp: body.timestamp || new Date().toISOString(),
    currentPage: body.currentPage || '/',
    villaId: body.villaId || null,
    currentStage: body.currentStage || 'greet',
    knownLeadData,
    context,
    capabilities: body.capabilities || {
      canVerifyAvailability: false,
      canCreateBooking: false,
      canSendEmail: false
    }
  }
}];

// ============================================================
// NŒUD 3 — Build Live Context
// Formate les données villas + lead en texte structuré pour le LLM
// Inspiré du pattern CieloBot "Build Live Context"
// ============================================================

const data = $input.first().json;
const { context, knownLeadData, currentStage, message, sessionId } = data;

// Timestamp et contexte temporel
const now = new Date();
const dateStr = now.toLocaleDateString('fr-FR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
const timeStr = now.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

// Formater les villas en texte structuré
const villas = Array.isArray(context.villas) ? context.villas : [];
const villaContextText = villas.length === 0
  ? 'Aucune villa disponible actuellement.'
  : villas.slice(0, 8).map(v => {
      const amenities = Array.isArray(v.amenities) ? v.amenities.join(', ') : 'Non spécifiés';
      const price = v.price_per_night ? `${v.price_per_night}€/nuit` : 'Prix sur demande';
      return `Villa : ${v.name}\n  Capacité : ${v.capacity || '?'} personnes\n  Prix : ${price}\n  Localisation : ${v.location || 'Martinique'}\n  Équipements : ${amenities}\n  Description : ${v.description ? v.description.slice(0, 200) : 'N/A'}`;
    }).join('\n\n');

// Formater le lead data connu
const lead = knownLeadData || {};
const leadLines = [];
if (lead.firstName) leadLines.push(`Prénom : ${lead.firstName}`);
if (lead.email) leadLines.push(`Email : ${lead.email}`);
if (lead.phone) leadLines.push(`Téléphone : ${lead.phone}`);
if (lead.totalGuests) leadLines.push(`Voyageurs : ${lead.totalGuests}`);
if (lead.checkIn) leadLines.push(`Arrivée : ${lead.checkIn}`);
if (lead.checkOut) leadLines.push(`Départ : ${lead.checkOut}`);
if (lead.villaPreference) leadLines.push(`Villa préférée : ${lead.villaPreference}`);
if (lead.budget) leadLines.push(`Budget : ${lead.budget}`);
if (lead.stayPurpose) leadLines.push(`Motif : ${lead.stayPurpose}`);
const knownLeadDataText = leadLines.length > 0 ? leadLines.join('\n') : 'Aucune information connue.';

// Disponibilités équipements
const amenitiesList = Array.isArray(context.availableAmenities)
  ? context.availableAmenities.join(', ')
  : 'Non spécifiés';

// Instructions spécifiques au stage courant
const stageInstructions = {
  greet: 'Accueillez chaleureusement. Posez une question ouverte pour comprendre l\'intention. Stage suivant : discover.',
  discover: 'Explorez les besoins : motif du séjour, nombre de voyageurs, dates approximatives. 1 question max. Stage suivant : clarify ou recommend.',
  clarify: 'Précisez les critères flous : dates exactes, capacité souhaitée. 1 question max. Stage suivant : recommend.',
  recommend: 'Présentez 1-2 villas pertinentes avec leurs points forts. Invitez à confirmer l\'intérêt. Stage suivant : qualify.',
  qualify: 'Collectez les slots manquants (email, téléphone si chaud). Max 2 questions regroupées logiquement. Stage suivant : verify.',
  verify: 'Récapitulez toutes les informations et demandez confirmation. 0 question. Stage suivant : prebook.',
  prebook: 'Confirmez la prise en charge. Annoncez le délai de retour. Stage suivant : handoff.',
  handoff: 'Clôturez avec un engagement de délai précis ("sous 2 heures"). Stage final.',
  fallback: 'Réorientez ou proposez un contact humain. 1 question max.'
};

const currentStageInstruction = stageInstructions[currentStage] || stageInstructions.greet;

// Construire le chatInput enrichi pour le LLM
const enrichedContext = {
  dateStr,
  timeStr,
  villaContextText,
  knownLeadDataText,
  amenitiesList,
  villaCount: context.villaCount || villas.length,
  currentStageInstruction,
  capabilities: data.capabilities || {}
};

return [{
  json: {
    ...data,
    enrichedContext,
    // chatInput sera le message brut envoyé au LLM
    chatInput: message
  }
}];

// ============================================================
// NŒUD 5 — Parse Response
// Extrait le JSON structuré depuis la réponse du LLM
// Pattern inspiré CieloBot : 3 tentatives de parsing
// ============================================================

const rawOutput = $input.first().json.output || $input.first().json.text || $input.first().json.reply || '';
const upstream = $input.first().json;

// Tenter d'extraire le JSON depuis la réponse
function extractJSON(text) {
  if (!text || typeof text !== 'string') return null;

  // Tentative 1 : parsing direct
  try {
    return JSON.parse(text.trim());
  } catch (_) {}

  // Tentative 2 : extraction du premier bloc {...}
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch (_) {}
  }

  // Tentative 3 : extraction depuis bloc ```json ... ```
  const codeBlock = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (codeBlock) {
    try {
      return JSON.parse(codeBlock[1].trim());
    } catch (_) {}
  }

  return null;
}

const parsed = extractJSON(rawOutput);

if (!parsed || typeof parsed.reply !== 'string' || !parsed.reply.trim()) {
  // Fallback gracieux
  return [{
    json: {
      ...upstream,
      parsedResponse: {
        reply: "Je rencontre une difficulté technique passagère. Notre équipe reste disponible pour vous accompagner.",
        intent: "unknown",
        stage: upstream.currentStage || "fallback",
        leadTemperature: upstream.knownLeadData?.temperature || "cold",
        leadUpdate: {},
        suggestedVillas: [],
        cta: { type: "none" },
        suggestedQuickReplies: ["Voir nos villas", "Contacter le concierge"],
        shouldEscalateToHuman: false,
        humanHandoffReason: null,
        warnings: ["parse_error"]
      },
      parseError: true
    }
  }];
}

// Nettoyer et valider le leadUpdate — ne garder que les champs non-null
const rawLeadUpdate = parsed.leadUpdate || {};
const cleanedLeadUpdate = {};
for (const [key, val] of Object.entries(rawLeadUpdate)) {
  if (val !== null && val !== undefined && val !== '') {
    cleanedLeadUpdate[key] = val;
  }
}

// Calculer le qualification score
const mergedLead = {
  ...(upstream.knownLeadData || {}),
  ...cleanedLeadUpdate
};
let score = 0;
if (mergedLead.totalGuests) score += 10;
if (mergedLead.checkIn) score += 15;
if (mergedLead.checkOut) score += 15;
if (mergedLead.email) score += 20;
if (mergedLead.phone) score += 15;
if (mergedLead.budget) score += 10;
if (mergedLead.stayPurpose) score += 15;

const leadTemperature = score > 50 ? 'hot' : score >= 20 ? 'warm' : 'cold';
const finalTemperature = parsed.leadTemperature || leadTemperature;

// Vérifier si pre-booking est prêt
const readyToPrebook = !!(mergedLead.checkIn && mergedLead.checkOut && mergedLead.totalGuests && mergedLead.email);
const missingFields = [];
if (!mergedLead.checkIn) missingFields.push('checkIn');
if (!mergedLead.checkOut) missingFields.push('checkOut');
if (!mergedLead.totalGuests) missingFields.push('totalGuests');
if (!mergedLead.email) missingFields.push('email');

return [{
  json: {
    ...upstream,
    parsedResponse: {
      ...parsed,
      leadUpdate: cleanedLeadUpdate,
      leadTemperature: finalTemperature,
      qualificationScore: score,
      suggestedVillas: Array.isArray(parsed.suggestedVillas) ? parsed.suggestedVillas.slice(0, 3) : [],
      suggestedQuickReplies: Array.isArray(parsed.suggestedQuickReplies) ? parsed.suggestedQuickReplies.slice(0, 4) : [],
      cta: parsed.cta || { type: 'none' },
      shouldEscalateToHuman: parsed.shouldEscalateToHuman === true,
      humanHandoffReason: parsed.shouldEscalateToHuman ? (parsed.humanHandoffReason || null) : null,
      warnings: Array.isArray(parsed.warnings) ? parsed.warnings : []
    },
    mergedLead,
    prebookingStatus: {
      readyToCreate: readyToPrebook,
      missingFields
    }
  }
}];

// ============================================================
// NŒUD 9 — Format Reply
// Prépare la réponse finale pour le webhook
// Construit le payload ChatbotResponse compatible Next.js
// ============================================================

const data = $input.first().json;
const { parsedResponse, sessionId, prebookingStatus } = data;

// Construire la réponse frontend-safe
const clientResponse = {
  success: true,
  reply: parsedResponse.reply,
  sessionId,
  intent: parsedResponse.intent || undefined,
  stage: parsedResponse.stage || 'greet',
  leadTemperature: parsedResponse.leadTemperature || 'cold',
  leadUpdate: parsedResponse.leadUpdate || {},
  suggestedVillas: Array.isArray(parsedResponse.suggestedVillas)
    ? parsedResponse.suggestedVillas.slice(0, 3)
    : [],
  cta: parsedResponse.cta || { type: 'none' },
  suggestedQuickReplies: Array.isArray(parsedResponse.suggestedQuickReplies)
    ? parsedResponse.suggestedQuickReplies.slice(0, 4)
    : [],
  shouldEscalateToHuman: parsedResponse.shouldEscalateToHuman === true,
  humanHandoffReason: parsedResponse.shouldEscalateToHuman
    ? (parsedResponse.humanHandoffReason || null)
    : undefined,
  // Inclure preBooking si prêt
  preBooking: prebookingStatus?.readyToCreate
    ? {
        readyToCreate: true,
        missingFields: []
      }
    : undefined,
  warnings: Array.isArray(parsedResponse.warnings) ? parsedResponse.warnings : []
};

// Supprimer les clés undefined pour un JSON propre
const cleanResponse = JSON.parse(JSON.stringify(clientResponse));

return [{ json: { clientResponse: cleanResponse } }];
